-- Modify "workflow_task_events" table
ALTER TABLE "workflow_task_events" ADD CONSTRAINT "workflow_task_events_receipt_v1_complete" CHECK (((idempotency_key IS NULL) AND (intent_hash IS NULL) AND (command_key IS NULL) AND (mutation_result IS NULL)) OR ((idempotency_key IS NOT NULL) AND ((length(TRIM(BOTH FROM idempotency_key)) >= 1) AND (length(TRIM(BOTH FROM idempotency_key)) <= 128)) AND (intent_hash IS NOT NULL) AND (length((intent_hash)::text) = 64) AND (command_key IS NOT NULL) AND ((length(TRIM(BOTH FROM command_key)) >= 1) AND (length(TRIM(BOTH FROM command_key)) <= 128)) AND (mutation_result IS NOT NULL) AND (task_version IS NOT NULL) AND (task_version > 0) AND (actor_id IS NOT NULL) AND (actor_id > 0) AND (to_status_key IS NOT NULL) AND (length(TRIM(BOTH FROM to_status_key)) > 0)));
